const getIcons = (type) => {
  const isSmall = type === "small";

  const adjustSize = (width, height) => ({
    width: isSmall ? width - differenceValue : width,
    height: isSmall ? height - differenceValue : height,
  });

  return Object.fromEntries(
    Object.entries(baseIcons).map(([key, { width, height, svg }]) => {
      const { width: w, height: h } = adjustSize(width, height);
      return [
        key,
        <svg
          xmlns="http://www.w3.org/2000/svg"
          width={w}
          height={h}
          viewBox={`0 0 ${width} ${height}`}
          fill="none"
          dangerouslySetInnerHTML={{ __html: svg }}
        />,
      ];
    })
  );
};

export default getIcons;
